// defaultAPIArtifactRE matches Gemini's "[image, generated by
// default_api:tool_name]" affordance — text fragments the model
// emits around a function_call to mark where the tool ran. The
// fragment is purely a model-to-itself signal; rendering it in
// the chat surface confuses the user, who sees the tool result
// directly. Match the closing form (with or without leading "[")
// since the chunk boundary often lands inside the bracket pair.
var defaultAPIArtifactRE = regexp.MustCompile(`\[?[a-zA-Z]*,?\s*generated by default_api:[a-zA-Z_]+\]?`)

// stripDefaultAPIArtifact removes Gemini's tool-call narration
// fragments from outbound text chunks. Empty result after strip
// → caller should skip the chunk entirely so the live UI doesn't
// flicker an empty bubble.
func stripDefaultAPIArtifact(s string) string {
	out := defaultAPIArtifactRE.ReplaceAllString(s, "")
	if out == s {
		// Regex didn't match — pass through verbatim. The TrimLeft
		// below is a cleanup pass for stray punctuation/whitespace
		// the strip leaves behind; running it on every chunk
		// silently ate the leading space of streaming deltas, so
		// " world" turned into "world" and successive chunks
		// concatenated as "worldisgreat" client-side. Only clean
		// up when we actually stripped something.
		return s
	}
	// Tidy up any leading/trailing whitespace + stray punctuation
	// the strip leaves behind (typically a leading ", " or ",
	// \n").
	out = strings.TrimLeft(out, " \t\n,;")
	return out
}

// errorReadLimit caps how much error-body we retain to surface in error
// messages. Gemini error payloads are typically <2k; bigger means something's
// wrong upstream and we don't want to log megabytes back.
const errorReadLimit = 8 * 1024

// --- Wire-shape types ----------------------------------------------------
//
// We intentionally model the request and response shapes here rather than
// pulling in the go-genai SDK — the surface is small, well-documented, and
// stable enough that a few hand-typed structs are easier to reason about
// (and easier to evolve) than wrapping the SDK.

// generateContentRequest is the body POSTed to streamGenerateContent.
type generateContentRequest struct {
	Contents          []geminiContent       `json:"contents,omitempty"`
	SystemInstruction *geminiContent        `json:"system_instruction,omitempty"`
	GenerationConfig  *generationConfig     `json:"generationConfig,omitempty"`
	SafetySettings    []geminiSafetySetting `json:"safetySettings,omitempty"`
	Tools             []geminiToolEntry     `json:"tools,omitempty"`

	// CachedContent references a previously-created cachedContents resource
	// (see Driver.CreateCachedContent). Format: "cachedContents/<id>". When
	// set, Gemini reuses the cached prefix and bills only the unique
	// suffix — usage shows up as cachedContentTokenCount.
	CachedContent string `json:"cachedContent,omitempty"`
}

// geminiToolEntry is one element of the request's `tools` array. Gemini
// groups function declarations under a single tool entry.
type geminiToolEntry struct {
	FunctionDeclarations []geminiFunctionDeclaration `json:"functionDeclarations"`
}

type geminiFunctionDeclaration struct {
	Name        string          `json:"name"`
	Description string          `json:"description,omitempty"`
	Parameters  json.RawMessage `json:"parameters,omitempty"`
}

type geminiContent struct {
	Role  string       `json:"role,omitempty"` // "user" or "model"; omitted for system_instruction
	Parts []geminiPart `json:"parts"`
}

// geminiPart is one element of a content's parts array. Exactly one of
// Text / FunctionCall / FunctionResponse is populated per part.
//
// ThoughtSignature lives at the part level (NOT nested inside
// functionCall) per Gemini's wire shape. It MUST round-trip back on the
// same part on the next request — Gemini rejects HTTP 400 with
// "Function call is missing a thought_signature" otherwise.
type geminiPart struct {
	Text             string              `json:"text,omitempty"`
	Thought          bool                `json:"thought,omitempty"`
	ThoughtSignature string              `json:"thoughtSignature,omitempty"`
	FunctionCall     *geminiFunctionCall `json:"functionCall,omitempty"`
	FunctionResponse *geminiFunctionResp `json:"functionResponse,omitempty"`
	// InlineData carries an attached binary payload — image, audio,
	// document — directly in the request. Gemini accepts up to a
	// few MB inline; larger uploads should go through the (deferred)
	// File API. Mutually exclusive with the other part fields.
	InlineData *geminiInlineData `json:"inlineData,omitempty"`
}

// geminiInlineData is Gemini's wire shape for an inline binary
// part (`{"inlineData":{"mimeType":...,"data":<base64>}}`).
type geminiInlineData struct {
	MimeType string `json:"mimeType"`
	Data     string `json:"data"`
}

// geminiFunctionCall is what Gemini emits when the model invokes a
// declared function. The thoughtSignature lives one level up on
// geminiPart — see that type's doc for round-trip rules.
type geminiFunctionCall struct {
	Name string          `json:"name"`
	Args json.RawMessage `json:"args,omitempty"`
}

// geminiFunctionResp carries tool output back to the model.
// Gemini documents `response` as an object; non-object payloads get
// wrapped via wrapAsObject.
type geminiFunctionResp struct {
	Name     string          `json:"name"`
	Response json.RawMessage `json:"response"`
}

type generationConfig struct {
	Temperature      *float64        `json:"temperature,omitempty"`
	TopP             *float64        `json:"topP,omitempty"`
	TopK             *int            `json:"topK,omitempty"`
	MaxOutputTokens  *int            `json:"maxOutputTokens,omitempty"`
	StopSequences    []string        `json:"stopSequences,omitempty"`
	CandidateCount   *int            `json:"candidateCount,omitempty"`
	ResponseMimeType *string         `json:"responseMimeType,omitempty"`
	ResponseSchema   json.RawMessage `json:"responseSchema,omitempty"`
	ThinkingConfig   *thinkingConfig `json:"thinkingConfig,omitempty"`
}

type thinkingConfig struct {
	IncludeThoughts *bool `json:"includeThoughts,omitempty"`
	ThinkingBudget  *int  `json:"thinkingBudget,omitempty"`
}

type geminiSafetySetting struct {
	Category  string `json:"category"`
	Threshold string `json:"threshold"`
}

// --- Streaming response shape -------------------------------------------

// streamEnvelope is one Server-Sent Event payload from streamGenerateContent.
//
// UsageMetadata is captured as raw JSON so we can store the original
// upstream bytes verbatim in messages.provider_usage_raw — preserving
// fields our typed struct doesn't know about (toolUsePromptTokenCount,
// the *TokensDetails per-modality breakdowns, future Gemini additions).
// The pump unmarshals the raw bytes into `usageMetadata` separately for
// typed access; both paths share the same source bytes so they can't
// drift.
type streamEnvelope struct {
	Candidates     []candidate      `json:"candidates,omitempty"`
	UsageMetadata  json.RawMessage  `json:"usageMetadata,omitempty"`
	PromptFeedback *json.RawMessage `json:"promptFeedback,omitempty"`
	Error          *geminiError     `json:"error,omitempty"`
}

type candidate struct {
	Content       geminiContent     `json:"content"`
	FinishReason  string            `json:"finishReason,omitempty"`
	Index         int               `json:"index,omitempty"`
	SafetyRatings []json.RawMessage `json:"safetyRatings,omitempty"`
}

// usageMetadata mirrors the v1 Gemini UsageMetadata shape from
// https://ai.google.dev/api/generate-content#UsageMetadata. We capture
// every documented field so cache/cost accounting reflects what the API
// actually reported, including the per-modality breakdowns. The raw
// bytes are stored separately on messages.provider_usage_raw — this
// struct is solely for typed access during the stream.
type usageMetadata struct {
	PromptTokenCount           int                  `json:"promptTokenCount,omitempty"`
	CandidatesTokenCount       int                  `json:"candidatesTokenCount,omitempty"`
	TotalTokenCount            int                  `json:"totalTokenCount,omitempty"`
	CachedContentTokenCount    int                  `json:"cachedContentTokenCount,omitempty"`
	ThoughtsTokenCount         int                  `json:"thoughtsTokenCount,omitempty"`
	ToolUsePromptTokenCount    int                  `json:"toolUsePromptTokenCount,omitempty"`
	PromptTokensDetails        []modalityTokenCount `json:"promptTokensDetails,omitempty"`
	CacheTokensDetails         []modalityTokenCount `json:"cacheTokensDetails,omitempty"`
	CandidatesTokensDetails    []modalityTokenCount `json:"candidatesTokensDetails,omitempty"`
	ToolUsePromptTokensDetails []modalityTokenCount `json:"toolUsePromptTokensDetails,omitempty"`
}

// modalityTokenCount is the per-modality token breakdown Gemini emits
// alongside the summary counts. We sum them as a fallback for
// CachedContentTokenCount since some models / API versions emit only
// the breakdown and not the summary.
type modalityTokenCount struct {
	Modality   string `json:"modality,omitempty"`
	TokenCount int    `json:"tokenCount,omitempty"`
}

// effectiveCacheReadTokens prefers the explicit summary; falls back to
// summing the per-modality breakdown so we don't miss cache data when
// Gemini emits one but not the other.
func (u usageMetadata) effectiveCacheReadTokens() int {
	if u.CachedContentTokenCount > 0 {
		return u.CachedContentTokenCount
	}
	sum := 0
	for _, m := range u.CacheTokensDetails {
		sum += m.TokenCount
	}
	return sum
}

type geminiError struct {
	Code    int    `json:"code,omitempty"`
	Message string `json:"message,omitempty"`
	Status  string `json:"status,omitempty"`
}

// --- Public API ---------------------------------------------------------

// Send dispatches a turn through Gemini's streamGenerateContent SSE endpoint
// and translates the upstream stream into the normalized chunk vocabulary
// defined by providers.Chunk.
//
// Event mapping:
//
//	candidates[].content.parts[].text (thought=true)  → ChunkThinking
//	candidates[].content.parts[].text (thought=false) → ChunkText
//	usageMetadata                                     → ChunkUsage
//	error                                             → ChunkError
//	(stream end)                                      → ChunkDone
//
// Non-2xx responses surface as a single ChunkError followed by ChunkDone
// (or, for pre-stream errors, an error from Send itself).
func (d *Driver) Send(ctx context.Context, req providers.SendRequest) (<-chan providers.Chunk, error) {
	if req.ModelID == "" {
		return nil, errors.New("google: model_id is required")
	}

	body, err := buildRequestBody(req)
	if err != nil {
		return nil, err
	}
	bodyJSON, err := json.Marshal(body)
	if err != nil {
		return nil, fmt.Errorf("google: marshal request: %w", err)
	}

	endpoint, err := d.streamEndpoint(req.ModelID)
	if err != nil {
		return nil, err
	}

	if os.Getenv("PSMITH_DEBUG_GEMINI_REQUEST") != "" {
		slog.Info("google: outgoing request", "model", req.ModelID, "body", string(bodyJSON))
	}

	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, endpoint, bytes.NewReader(bodyJSON))
	if err != nil {
		return nil, fmt.Errorf("google: build request: %w", err)
	}
	httpReq.Header.Set("Content-Type", "application/json")
	httpReq.Header.Set("Accept", "text/event-stream")
	// Auth via header, never the URL: ?key= leaks into every error
	// message that wraps a URL (context-deadline failures, 4xx logs,
	// upstream proxies). The x-goog-api-key header keeps the secret
	// off any stringified URL.
	httpReq.Header.Set("x-goog-api-key", d.cfg.APIKey)

	resp, err := d.httpClient.Do(httpReq)
	if err != nil {
		return nil, fmt.Errorf("google: send: %w", err)
	}

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		body := readBoundedError(resp)
		_ = resp.Body.Close()
		// Surface the failure as a chunk + Done so the supervisor's normal
		// terminal-state handling fires. We could equivalently return an
		// error from Send; the supervisor handles both, but the chunk path
		// keeps behaviour closer to the OpenAI/Anthropic streams which only
		// fail mid-stream.
		out := make(chan providers.Chunk, 2)
		emit(out, providers.ChunkError, map[string]any{
			"message": fmt.Sprintf("HTTP %d: %s", resp.StatusCode, body),
			"code":    fmt.Sprintf("%d", resp.StatusCode),
		})
		emit(out, providers.ChunkDone, map[string]any{})
		close(out)
		return out, nil
	}

	out := make(chan providers.Chunk, 16)
	go d.pumpStream(ctx, resp.Body, out)
	return out, nil
}

// streamEndpoint builds the SSE URL:
// /v1beta/models/{model}:streamGenerateContent?alt=sse
// The API key rides the x-goog-api-key header on the request (set by
// the caller) — never as a query parameter, since the URL ends up
// embedded in error messages and proxy logs.
func (d *Driver) streamEndpoint(modelID string) (string, error) {
	u, err := url.Parse(d.baseURL + "/models/" + url.PathEscape(modelID) + ":streamGenerateContent")
	if err != nil {
		return "", fmt.Errorf("google: build endpoint: %w", err)
	}
	q := u.Query()
	q.Set("alt", "sse")
	u.RawQuery = q.Encode()
	return u.String(), nil
}

// pumpStream consumes the SSE body, decodes per-event JSON envelopes, and
// translates them into the chunk vocabulary. It always emits exactly one
// ChunkDone before closing the channel — even on error paths, so subscribers
// see a clean terminator.
func (d *Driver) pumpStream(ctx context.Context, body io.ReadCloser, out chan<- providers.Chunk) {
	defer close(out)
	defer body.Close()

	// Aggregate usage across the stream. Gemini emits usageMetadata on the
	// final event, but in practice it can show up on any event — keep the
	// last-seen values and emit one ChunkUsage right before ChunkDone.
	var lastUsage *usageMetadata
	var lastUsageRaw json.RawMessage
	// FinishReason on the candidate also typically appears on the last
	// event but isn't guaranteed — last-write wins.
	var lastFinishReason string

	scanner := bufio.NewScanner(body)
	// Allow large SSE events — Gemini frames can include long thought blocks.
	buf := make([]byte, 0, 64*1024)
	scanner.Buffer(buf, 1024*1024)

	// Synthetic id sequence for tool calls (Gemini doesn't return ids).
	fcSeq := 0

	var dataAccum strings.Builder
	flush := func() bool {
		if dataAccum.Len() == 0 {
			return true
		}
		raw := dataAccum.String()
		dataAccum.Reset()
		// Skip explicit terminators just in case (Gemini doesn't send "[DONE]"
		// but mirroring OpenAI behaviour costs nothing).
		if strings.TrimSpace(raw) == "[DONE]" {
			return true
		}
		var env streamEnvelope
		if err := json.Unmarshal([]byte(raw), &env); err != nil {
			emit(out, providers.ChunkError, map[string]string{
				"message": fmt.Sprintf("decode SSE event: %v", err),
			})
			return true
		}
		if env.Error != nil {
			emit(out, providers.ChunkError, map[string]any{
				"message": env.Error.Message,
				"code":    env.Error.Status,
			})
		}
		for _, c := range env.Candidates {
			if c.FinishReason != "" {
				lastFinishReason = c.FinishReason
			}
			for _, p := range c.Content.Parts {
				if p.FunctionCall != nil {
					emitGeminiToolCall(out, p.FunctionCall, p.ThoughtSignature, &fcSeq)
					continue
				}
				if p.Text == "" {
					continue
				}
				if p.Thought {
					emit(out, providers.ChunkThinking, map[string]string{"text": p.Text})
				} else {
					// Gemini wraps function_calls with a "[image,
					// generated by default_api:tool]" affordance.
					// Strip the marker before forwarding — it's a
					// model-internal signal, not user-facing
					// text.
					cleaned := stripDefaultAPIArtifact(p.Text)
					if cleaned == "" {
						continue
					}
					emit(out, providers.ChunkText, map[string]string{"text": cleaned})
				}
			}
		}
		if len(env.UsageMetadata) > 0 {
			// Store the upstream bytes verbatim so the DB's
			// provider_usage_raw column reflects what Gemini actually
			// sent — including fields our typed struct doesn't model
			// (toolUsePrompt counters, *TokensDetails breakdowns,
			// future API additions). Then parse a typed view for our
			// own accounting; if the parse fails we still keep the raw
			// bytes around for forensics.
			lastUsageRaw = env.UsageMetadata
			var um usageMetadata
			if err := json.Unmarshal(env.UsageMetadata, &um); err == nil {
				lastUsage = &um
			}
		}
		return true
	}

	for scanner.Scan() {
		select {
		case <-ctx.Done():
			emit(out, providers.ChunkError, map[string]string{"message": ctx.Err().Error()})
			emit(out, providers.ChunkDone, map[string]any{})
			return
		default:
		}
		line := scanner.Text()
		if line == "" {
			// SSE event boundary.
			if !flush() {
				return
			}
			continue
		}
		// SSE format: lines starting with "data: " carry the payload; ":"
		// is a comment, anything else (event:, id:) is metadata we ignore.
		if strings.HasPrefix(line, ":") {
			continue
		}
		if strings.HasPrefix(line, "data:") {
			payload := strings.TrimPrefix(line, "data:")
			payload = strings.TrimPrefix(payload, " ")
			if dataAccum.Len() > 0 {
				dataAccum.WriteByte('\n')
			}
			dataAccum.WriteString(payload)
		}
		// "event:", "id:", "retry:" lines are silently dropped — Gemini
		// doesn't use them but the format allows them.
	}
	// Trailing event without a blank line terminator.
	flush()

	if err := scanner.Err(); err != nil && !errors.Is(err, io.EOF) {
		emit(out, providers.ChunkError, map[string]string{"message": err.Error()})
	}

	// Order matters here. openStreamWithRetry treats a ChunkError as
	// the FIRST chunk as "transient failure, retry from scratch" — a
	// Gemini MALFORMED_FUNCTION_CALL run typically produces zero text
	// + zero tool-use chunks, so without usage in front the error
	// would arrive first and trigger 3x prompt billing for the same
	// deterministic failure. Emitting usage first guarantees the
	// supervisor's openOnce sees a non-error first chunk → success
	// path → consume loop reads the trailing error normally and
	// marks the message as errored (one billing, one error).
	if lastUsage != nil {
		emitUsage(out, *lastUsage, lastUsageRaw, lastFinishReason)
	}
	// Only "hard" failure-shaped finish reasons (system-level: malformed
	// tool calls, OTHER) get surfaced as ChunkError so the supervisor
	// marks the message as errored + offers retry. Safety-block reasons
	// (SAFETY, RECITATION, BLOCKLIST, PROHIBITED_CONTENT, SPII,
	// IMAGE_SAFETY) ride finish_reason alone — they're the model's
	// considered decision not to respond, not a system failure, and the
	// UI surfaces unexpected finish reasons as a "Stopped: …" hint on
	// the assistant row without the red error banner / retry chrome.
	if msg := geminiHardFailureMessage(lastFinishReason); msg != "" {
		emit(out, providers.ChunkError, map[string]string{
			"message": msg,
			"code":    lastFinishReason,
		})
	}
	emit(out, providers.ChunkDone, map[string]any{})
}

// geminiHardFailureMessage maps a system-level failure finish reason
// to a user-facing error string. Returns "" for clean stops AND for
// safety-block reasons (which are the model's deliberate choice not to
// respond and ride finish_reason alone via the UI's "Stopped: …" hint
// — see Message.finish_reason rendering). Lists from the GenerateContent
// API spec; unknown reasons fall through to "" so a new server-side
// enum value doesn't accidentally start erroring runs.
func geminiHardFailureMessage(reason string) string {
	switch reason {
	case "MALFORMED_FUNCTION_CALL":
		return "Gemini tried to call a tool but the call was malformed (invalid JSON args or unknown function). Try rephrasing or removing the active tool."
	case "OTHER":
		return "Gemini stopped with an unspecified failure (finish_reason=OTHER)."
	}
	return ""
}

// emitGeminiToolCall translates one functionCall part into the
// supervisor's three-chunk tool_use sequence. The part-level
// thoughtSignature rides the Start chunk as `provider_opaque` so the
// loop wrapper can stash it on the ToolUseBlock and the next-round
// emit reattaches it.
func emitGeminiToolCall(out chan<- providers.Chunk, fc *geminiFunctionCall, thoughtSignature string, seq *int) {
	*seq++
	id := makeGeminiToolID(fc.Name, *seq)
	startPayload := map[string]string{
		"id":   id,
		"name": fc.Name,
	}
	if thoughtSignature != "" {
		startPayload["provider_opaque"] = thoughtSignature
	}
	emit(out, providers.ChunkToolUseStart, startPayload)
	args := fc.Args
	if len(args) == 0 {
		args = json.RawMessage(`{}`)
	}
	emit(out, providers.ChunkToolUseDelta, map[string]string{
		"partial_json": string(args),
	})
	emit(out, providers.ChunkToolUseEnd, map[string]any{})
}

// emitUsage normalizes a usageMetadata into ChunkUsage. Cache reads
// map to cache_read_tokens via effectiveCacheReadTokens() — prefers
// the explicit CachedContentTokenCount summary, falls back to summing
// the per-modality CacheTokensDetails breakdown when the summary is
// absent (some Gemini models / API versions emit one but not both).
// ThoughtsTokenCount maps to reasoning_tokens.
func emitUsage(out chan<- providers.Chunk, u usageMetadata, raw json.RawMessage, finishReason string) {
	// Gemini reports `promptTokenCount` as the GROSS prompt count
	// (including cached) and `cachedContentTokenCount` (or the
	// per-modality breakdown) as the cached subset. Subtract here so
	// the supervisor's cost calc doesn't bill the cached portion at
	// both the fresh-input and cache-read rates.
	cached := u.effectiveCacheReadTokens()
	in := u.PromptTokenCount - cached
	if in < 0 {
		in = 0
	}
	outTok := u.CandidatesTokenCount
	usage := providers.Usage{}
	if in > 0 {
		usage.InputTokens = &in
	}
	if outTok > 0 {
		usage.OutputTokens = &outTok
	}
	if cached > 0 {
		v := cached
		usage.CacheReadTokens = &v
	}
	if u.ThoughtsTokenCount > 0 {
		v := u.ThoughtsTokenCount
		usage.ReasoningTokens = &v
	}
	if usage.InputTokens == nil && usage.OutputTokens == nil &&
		usage.CacheReadTokens == nil && usage.ReasoningTokens == nil {
		return
	}
	usage.ProviderRaw = raw
	if finishReason != "" {
		fr := finishReason
		usage.FinishReason = &fr
	}
	payload, err := json.Marshal(usage)
	if err != nil {
		return
	}
	out <- providers.Chunk{Type: providers.ChunkUsage, Payload: payload}
}

// emit marshals and pushes one chunk. JSON-marshal failures fall back to "{}"
// — the payloads in this driver are static maps and never fail in practice.
func emit(out chan<- providers.Chunk, typ providers.ChunkType, payload any) {
	raw, err := json.Marshal(payload)
	if err != nil {
		raw = []byte(`{}`)
	}
	out <- providers.Chunk{Type: typ, Payload: raw}
}

// readBoundedError reads up to errorReadLimit bytes from a non-2xx response
// body for use in error messages. Doesn't close the body.
func readBoundedError(resp *http.Response) string {
	if resp == nil || resp.Body == nil {
		return ""
	}
	r := io.LimitReader(resp.Body, errorReadLimit)
	b, _ := io.ReadAll(r)
	return strings.TrimSpace(string(b))
}

// --- Request building ---------------------------------------------------

// buildRequestBody translates Psmith's wire shape into Gemini's request body.
//
// Roles:
//   - "system" → system_instruction (separate field; not part of contents).
//     Multiple system messages concatenate into a single system_instruction
//     with one part per message — Gemini accepts multiple parts.
//   - "user"   → contents[] role="user".
//   - "assistant" → contents[] role="model" (Gemini's name for the assistant
//     side).
//
// CallSettings translation:
//   - common temperature/top_p/top_k/max_output_tokens/stop_sequences →
//     generationConfig.{temperature, topP, topK, maxOutputTokens, stopSequences}.
//   - Thinking.{Enabled, BudgetTokens} → generationConfig.thinkingConfig.
//   - Google extras (safety, response_mime_type, response_schema, candidate_count) → corresponding fields.
//
// Unsupported fields are silently dropped — driver translation is intentionally
// lossy on the way down (the per-driver test suite asserts the wire shape).
func buildRequestBody(req providers.SendRequest) (*generateContentRequest, error) {
	body := &generateContentRequest{}

	for _, m := range req.Messages {
		switch m.Role {
		case "system":
			if body.SystemInstruction == nil {
				body.SystemInstruction = &geminiContent{}
			}
			body.SystemInstruction.Parts = append(body.SystemInstruction.Parts, geminiPart{
				Text: m.Content,
			})
		case "user":
			body.Contents = append(body.Contents, geminiContent{
				Role:  "user",
				Parts: userPartsFromWire(m),
			})
		case "assistant":
			// Reconstruct the full parts array Gemini originally
			// returned: thought parts (if any) followed by the
			// answer text. Per Gemini's docs, prior thoughts must be
			// passed back verbatim for both prefix-cache stability
			// AND for the model to maintain reasoning context across
			// turns. Without this, every assistant turn carrying
			// thinking blocks would silently bust implicit caching.
			parts := assistantPartsFromWire(m)
			body.Contents = append(body.Contents, geminiContent{
				Role:  "model",
				Parts: parts,
			})
		default:
			return nil, fmt.Errorf("google: unsupported wire role %q", m.Role)
		}
	}

	gc := generationConfigFromSettings(req.Settings)
	if gc != nil {
		body.GenerationConfig = gc
	}

	if g := req.Settings.Google; g != nil {
		if g.SafetySettings != nil {
			body.SafetySettings = safetySettingsToWire(g.SafetySettings)
		}
		if g.CachedContent != nil && *g.CachedContent != "" {
			body.CachedContent = *g.CachedContent
		}
	}

	if len(req.Tools) > 0 {
		body.Tools = []geminiToolEntry{
			{FunctionDeclarations: toolsToFunctionDeclarations(req.Tools)},
		}
	}

	return body, nil
}

// toolsToFunctionDeclarations maps the driver-facing ToolDef list into
// Gemini's flat list of functionDeclarations. Parameter schemas are
// sanitized for the subset Gemini's OpenAPI Schema dialect accepts —
// see sanitizeGeminiSchema for the field list (chief offender is
// `additionalProperties`, which Anthropic + OpenAI accept fine but
// Gemini rejects with HTTP 400 "Cannot find field").
func toolsToFunctionDeclarations(tools []providers.ToolDef) []geminiFunctionDeclaration {
	out := make([]geminiFunctionDeclaration, 0, len(tools))
	for _, t := range tools {
		params := t.InputSchema
		if len(params) == 0 {
			params = json.RawMessage(`{"type":"object"}`)
		}
		out = append(out, geminiFunctionDeclaration{
			Name:        t.Name,
			Description: t.Description,
			Parameters:  sanitizeGeminiSchema(params),
		})
	}
	return out
}

// geminiUnsupportedSchemaKeys lists JSON Schema fields the Gemini
// OpenAPI Schema dialect rejects with HTTP 400. Stripped recursively
// in sanitizeGeminiSchema. The list is conservative — keys we know
// rejection-fail real requests in production, not "might be ignored."
//
// Reference: https://ai.google.dev/api/caching#Schema (the subset of
// OpenAPI 3.0 Gemini honors). The big-ticket missing fields:
//
//   - additionalProperties — common JSON Schema idiom for "no extra
//     keys allowed." Gemini interprets schemas as closed by default
//     so the flag is redundant; emitting it triggers the 400.
//   - $schema — meta-version marker; never useful for tool params.
//   - $defs / definitions — reference shapes the dialect doesn't
//     support inline expansion of; tools that need them are out of
//     scope until we add ref-expansion.
var geminiUnsupportedSchemaKeys = []string{
	"additionalProperties",
	"$schema",
	"$defs",
	"definitions",
}

// sanitizeGeminiSchema returns a JSON Schema with every
// geminiUnsupportedSchemaKeys entry removed, recursively. Falls back
// to the raw input when parsing fails — a malformed schema is
// upstream's problem to reject, not ours to mask.
func sanitizeGeminiSchema(raw json.RawMessage) json.RawMessage {
	if len(raw) == 0 {
		return raw
	}
	var v any
	if err := json.Unmarshal(raw, &v); err != nil {
		return raw
	}
	cleaned := stripGeminiKeys(v)
	out, err := json.Marshal(cleaned)
	if err != nil {
		return raw
	}
	return out
}

// stripGeminiKeys walks a parsed JSON Schema tree and removes any
// unsupported keys at every nesting depth. Operates on the generic
// `any` shape json.Unmarshal produces; collections recurse into
// elements, scalars pass through unchanged.
func stripGeminiKeys(v any) any {
	switch t := v.(type) {
	case map[string]any:
		for _, key := range geminiUnsupportedSchemaKeys {
			delete(t, key)
		}
		for k, child := range t {
			t[k] = stripGeminiKeys(child)
		}
		return t
	case []any:
		for i, child := range t {
			t[i] = stripGeminiKeys(child)
		}
		return t
	default:
		return v
	}
}

// userPartsFromWire builds the parts array for a user-role content,
// emitting functionResponse parts for any tool results in the message.
// Gemini identifies tool calls by name (no id), so we encode the name
// in the synthetic id we mint on inbound (see makeGeminiToolID) and
// recover it here via nameFromGeminiToolID.
func userPartsFromWire(m providers.WireMessage) []geminiPart {
	parts := []geminiPart{}
	for _, tr := range m.ToolResults {
		name := nameFromGeminiToolID(tr.ToolUseID)
		var responseObj json.RawMessage
		if tr.Error != "" {
			payload, _ := json.Marshal(map[string]string{"error": tr.Error})
			responseObj = payload
		} else if len(tr.Output) > 0 {
			responseObj = wrapAsObject(tr.Output)
		} else {
			responseObj = json.RawMessage(`{}`)
		}
		parts = append(parts, geminiPart{
			FunctionResponse: &geminiFunctionResp{
				Name:     name,
				Response: responseObj,
			},
		})
		// Gemini's functionResponse part can't itself carry
		// inline image content, so each tool-produced
		// attachment ships as a sibling inlineData part on the
		// same user content. The model treats them as part of
		// the function's "answer" because they immediately
		// follow the functionResponse part — the only ordering
		// signal Gemini exposes here.
		for _, att := range tr.Attachments {
			if len(att.Data) == 0 || att.MimeType == "" {
				continue
			}
			parts = append(parts, geminiPart{
				InlineData: &geminiInlineData{
					MimeType: att.MimeType,
					Data:     base64.StdEncoding.EncodeToString(att.Data),
				},
			})
		}
	}
	// Attachments → inlineData parts. Gemini supports all four
	// kinds (image, document, audio, video) via the same
	// inline_data shape — the model dispatches on mime_type.
	// v1 inlines bytes; the Files API path is phase 4. Empty-
	// data attachments are a history-builder bug; drop silently.
	for _, att := range m.Attachments {
		if len(att.Data) == 0 || att.MimeType == "" {
			continue
		}
		switch att.Kind {
		case providers.AttachmentImage,
			providers.AttachmentDocument,
			providers.AttachmentAudio,
			providers.AttachmentVideo:
			parts = append(parts, geminiPart{
				InlineData: &geminiInlineData{
					MimeType: att.MimeType,
					Data:     base64.StdEncoding.EncodeToString(att.Data),
				},
			})
		}
	}
	if m.Content != "" {
		parts = append(parts, geminiPart{Text: m.Content})
	}
	if len(parts) == 0 {
		// Gemini rejects empty contents with "parts[*].data: required
		// oneof field 'data' must have one initialized field." Emitting
		// geminiPart{Text: ""} doesn't help because the struct's
		// `text,omitempty` tag strips the empty string → serialized as
		// {} → oneof unset. A single space survives the omitempty trim
		// and Gemini accepts it without distorting the model's view of
		// the turn. This branch fires when the wire-build produced a
		// truly empty user content (no text, no attachments that
		// survived the filter, no tool results) — defensive fallback
		// so we never POST `{ "parts": [{}] }`.
		parts = append(parts, geminiPart{Text: " "})
	}
	return parts
}

// wrapAsObject ensures `response` is a JSON object — Gemini requires
// an object even when the tool returned an array or primitive.
func wrapAsObject(raw json.RawMessage) json.RawMessage {
	trimmed := bytes.TrimSpace([]byte(raw))
	if len(trimmed) > 0 && trimmed[0] == '{' {
		return raw
	}
	wrapper, err := json.Marshal(map[string]json.RawMessage{"result": raw})
	if err != nil {
		return json.RawMessage(`{}`)
	}
	return wrapper
}

const geminiToolIDPrefix = "gem-fc-"

func makeGeminiToolID(name string, seq int) string {
	return fmt.Sprintf("%s%s-%d", geminiToolIDPrefix, name, seq)
}

func nameFromGeminiToolID(id string) string {
	if !strings.HasPrefix(id, geminiToolIDPrefix) {
		return id
	}
	body := strings.TrimPrefix(id, geminiToolIDPrefix)
	if idx := strings.LastIndex(body, "-"); idx > 0 {
		return body[:idx]
	}
	return body
}

// assistantPartsFromWire reconstructs the parts array for an assistant
// turn going BACK out to Gemini. If WireMessage.Thinking carries a
// previously-stored thought block (Psmith's storage shape:
// `[{"type":"text","text":"<concatenated thoughts>"}]`), prepend it as
// a thought part before the answer text. Falls back to a bare text
// part when there's no stored thinking — the common case for
// conversations that haven't enabled includeThoughts.
//
// Per https://ai.google.dev/gemini-api/docs/thinking the prior thought
// blocks must round-trip on the wire for the model to maintain
// reasoning context AND for the prefix-cache key to remain stable
// across turns. Stripping them silently busts implicit caching.
func assistantPartsFromWire(m providers.WireMessage) []geminiPart {
	parts := []geminiPart{}
	if len(m.Thinking) > 0 {
		var blocks []struct {
			Text string `json:"text"`
			Type string `json:"type"`
		}
		if err := json.Unmarshal(m.Thinking, &blocks); err == nil {
			for _, b := range blocks {
				if b.Text == "" {
					continue
				}
				parts = append(parts, geminiPart{Text: b.Text, Thought: true})
			}
		}
	}
	if m.Content != "" {
		parts = append(parts, geminiPart{Text: m.Content})
	}
	for _, tu := range m.ToolUses {
		args := tu.Input
		if len(args) == 0 {
			args = json.RawMessage(`{}`)
		}
		// thoughtSignature belongs ONLY at the part level on the wire —
		// Gemini rejects HTTP 400 with "Unknown name 'thoughtSignature'"
		// when nested inside functionCall.
		parts = append(parts, geminiPart{
			ThoughtSignature: tu.ProviderOpaque,
			FunctionCall: &geminiFunctionCall{
				Name: tu.Name,
				Args: args,
			},
		})
	}
	if len(parts) == 0 {
		// Same omitempty trap as userPartsFromWire — empty text strips
		// to {} and Gemini rejects the oneof. Single space survives.
		parts = append(parts, geminiPart{Text: " "})
	}
	return parts
}

// generationConfigFromSettings collapses CallSettings into Gemini's
// generationConfig. Returns nil if every field is empty so the field is
// omitted from the wire entirely.
func generationConfigFromSettings(s providers.CallSettings) *generationConfig {
	gc := &generationConfig{}
	any := false
	if s.Temperature != nil {
		gc.Temperature = s.Temperature
		any = true
	}
	if s.TopP != nil {
		gc.TopP = s.TopP
		any = true
	}
	if s.TopK != nil {
		gc.TopK = s.TopK
		any = true
	}
	if s.MaxOutputTokens != nil {
		gc.MaxOutputTokens = s.MaxOutputTokens
		any = true
	}
	if len(s.StopSequences) > 0 {
		gc.StopSequences = append([]string(nil), s.StopSequences...)
		any = true
	}
	if t := s.Thinking; t != nil {
		tc := &thinkingConfig{}
		set := false
		if t.Enabled != nil {
			tc.IncludeThoughts = t.Enabled
			set = true
		}
		if t.BudgetTokens != nil {
			tc.ThinkingBudget = t.BudgetTokens
			set = true
		}
		if set {
			gc.ThinkingConfig = tc
			any = true
		}
	}
	if g := s.Google; g != nil {
		if g.ResponseMimeType != nil && *g.ResponseMimeType != "" {
			gc.ResponseMimeType = g.ResponseMimeType
			any = true
		}
		if len(g.ResponseSchema) > 0 {
			// The schema field on the wire takes a parsed JSON value, not a
			// string. Round-trip the bytes so we don't double-encode them.
			var decoded json.RawMessage
			if err := json.Unmarshal(g.ResponseSchema, &decoded); err == nil {
				gc.ResponseSchema = decoded
			} else {
				// Malformed bytes — pass them through; the API will reject.
				gc.ResponseSchema = json.RawMessage(g.ResponseSchema)
			}
			any = true
		}
		if g.CandidateCount != nil {
			gc.CandidateCount = g.CandidateCount
			any = true
		}
	}
	if !any {
		return nil
	}
	return gc
}

// safetySettingsToWire translates Psmith's SafetySettings struct into the
// Gemini wire shape. Each non-nil threshold becomes one entry. Unset
// thresholds are simply omitted (Gemini falls back to its default).
func safetySettingsToWire(s *providers.SafetySettings) []geminiSafetySetting {
	if s == nil {
		return nil
	}
	var out []geminiSafetySetting
	addIf := func(category string, t *providers.HarmThreshold) {
		if t == nil {
			return
		}
		threshold := harmThresholdToWire(*t)
		if threshold == "" {
			return // unspecified — drop
		}
		out = append(out, geminiSafetySetting{
			Category:  category,
			Threshold: threshold,
		})
	}
	addIf("HARM_CATEGORY_HARASSMENT", s.Harassment)
	addIf("HARM_CATEGORY_HATE_SPEECH", s.HateSpeech)
	addIf("HARM_CATEGORY_SEXUALLY_EXPLICIT", s.SexuallyExplicit)
	addIf("HARM_CATEGORY_DANGEROUS_CONTENT", s.DangerousContent)
	return out
}

// harmThresholdToWire maps Psmith's enum to Gemini's enum strings.
func harmThresholdToWire(t providers.HarmThreshold) string {
	switch t {
	case providers.HarmThresholdBlockNone:
		return "BLOCK_NONE"
	case providers.HarmThresholdBlockLowAndAbove:
		return "BLOCK_LOW_AND_ABOVE"
	case providers.HarmThresholdBlockMediumAndAbove:
		return "BLOCK_MEDIUM_AND_ABOVE"
	case providers.HarmThresholdBlockOnlyHigh:
		return "BLOCK_ONLY_HIGH"
	}
	return ""
}
